$servers = @("DC01", "DC02", "FS01", "RDS01")
$criticalCount = 0

foreach ($server in $servers) {
    try {
        $responseTime = Get-Random -Minimum 1 -Maximum 100
        if ($responseTime -lt 30) {
            $status = "Ready"
        } elseif ($responseTime -le 70) {
            $status = "Degraded"
        } else {
            $status = "Critical"
            $criticalCount++
        }
        Write-Host "[$status] $server - Response time: $responseTime ms"
    }
    catch {
        Write-Host "Error checking $server: $($_.Exception.Message)"
    }
}

switch ($criticalCount) {
    {$_ -gt 2} { Write-Host "ALERT: Critical infrastructure failure imminent!" }
    {$_ -ge 1 -and $_ -le 2} { Write-Host "WARNING: Some servers are degraded" }
    default { Write-Host "OK: Infrastructure healthy" }
}
