function Check-Services {
    param([string]$Computer)
    $services = @("NTDS", "DNS", "DFS", "RDS")
    $serviceStatus = @()
    foreach ($svc in $services) {
        try {
            $service = Get-Service -ComputerName $Computer -Name $svc -ErrorAction Stop
            if ($service.Status -ne "Running") {
                $criticalIssues += "Service $svc is $($service.Status) on $Computer"
                $serviceStatus += "$svc: CRITICAL ($($service.Status))"
            } else {
                $serviceStatus += "$svc: OK"
            }
        }
        catch {
            $serviceStatus += "$svc: ERROR ($_)"
        }
    }
    return ($serviceStatus -join "; ")
}

function Check-Network {
    param([string]$Computer)
    $targets = @("172.16.0.1", "172.16.0.10")
    $networkStatus = @()
    foreach ($target in $targets) {
        try {
            $ping = Test-Connection -ComputerName $Computer -TargetName $target -Count 1 -Quiet -ErrorAction Stop
            if (-not $ping) {
                $criticalIssues += "Cannot reach $target from $Computer"
                $networkStatus += "$target: CRITICAL (unreachable)"
            } else {
                $networkStatus += "$target: OK"
            }
        }
        catch {
            $networkStatus += "$target: ERROR ($_)"
        }
    }
    return ($networkStatus -join "; ")
}

# Main execution
$healthReport = [PSCustomObject]@{
    ComputerName = $ComputerName
    CPU = Check-CPU -Computer $ComputerName
    RAM = Check-RAM -Computer $ComputerName
    Disks = Check-Disks -Computer $ComputerName
    Services = Check-Services -Computer $ComputerName
    Network = Check-Network -Computer $ComputerName
}

$healthReport | Format-List

if ($criticalIssues.Count -gt 0) {
    Write-Host "CRITICAL: $ComputerName - $($criticalIssues -join '; ')" -ForegroundColor Red
    exit 1
}
else {
    Write-Host "All checks passed for $ComputerName" -ForegroundColor Green
    exit 0
}
